    date: "2021-01-31",
    category: "Acupuncture",
    tags: ["Acupuncture","acupuncture in Jacksonville","acupuncture near me","end endo","endometriosis","Fertility Clinic","Health Pointe Jacksonville","ICSI","infertility","IUI","IVF","Jacksonville fertility","Julee Miller","PCOS","TTC","uterine health"],
    image: "/images/logo.png",
